# Extract human messages from all major sessions to understand what Roy does
# Parse jsonl files for role:user content
python3 -c "
import json, glob, os

sessions = {}
for f in glob.glob(os.path.expanduser('~/.claude/projects/**/*.jsonl'), recursive=True):
    project = f.split('/.claude/projects/')[1].split('/')[0]
    try:
        with open(f) as fh:
            msgs = []
            for line in fh:
                try:
                    d = json.loads(line)
                    if d.get('type') == 'user':
                        content = d.get('message', {}).get('content', '')
                        if isinstance(content, list):
                            for block in content:
                                if isinstance(block, dict) and block.get('type') == 'text':
                                    text = block['text'].strip()
                                    if text and len(text) > 10 and not text.startswith('<'):
                                        msgs.append(text[:200])
                        elif isinstance(content, str) and len(content) > 10:
                            if not content.startswith('<'):
                                msgs.append(content[:200])
                except:
                    pass
            if msgs:
                sessions.setdefault(project, []).extend(msgs)
    except:
        pass

for proj, msgs in sessions.items():
    print(f'\n=== {proj} ({len(msgs)} msgs) ===')
    for m in msgs[:30]:
        print(f'  - {m[:150]}')
" 2>/dev/null

